/* =============================================================================
   AURA ALPHA -- Position Management
   Scale in/out, portfolio rebalancing, order queue, execution history.
   Route: /position-management
   ============================================================================= */
import { useState, useEffect, useCallback, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import AnimatedPage, { staggerContainer, staggerItem } from '../components/AnimatedPage';
import usePageTitle from '../hooks/usePageTitle';
import useIsMobile from '../hooks/useIsMobile';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';
import s from './PositionManagementPage.module.css';

// -- Design tokens (kept for dynamic color logic only) ------------------------
const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  textMuted: tokens.color.textMuted, green: tokens.color.green, red: tokens.color.red,
  blue: tokens.color.blue, amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
};

// -- Formatters ---------------------------------------------------------------
function fmtDollar(v) {
  if (v == null || !isFinite(v)) return '--';
  if (Math.abs(v) >= 1e6) return `$${(v / 1e6).toFixed(1)}M`;
  if (Math.abs(v) >= 1e3) return `$${(v / 1e3).toFixed(1)}K`;
  return `$${v.toFixed(2)}`;
}
function fmtPct(v) {
  if (v == null || !isFinite(v)) return '--';
  return `${v >= 0 ? '+' : ''}${v.toFixed(2)}%`;
}
function pnlColor(v) {
  if (v == null || v === 0) return C.textSecondary;
  return v > 0 ? C.green : C.red;
}
function timeAgo(iso) {
  if (!iso) return '';
  const diff = Date.now() - new Date(iso).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return 'just now';
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}

// -- Animations ---------------------------------------------------------------
const fadeIn = {
  initial: { opacity: 0, y: 12 },
  animate: { opacity: 1, y: 0, transition: { duration: 0.25 } },
  exit: { opacity: 0, y: -8, transition: { duration: 0.15 } },
};

// -- Tabs ---------------------------------------------------------------------
const tabNames = ['Positions', 'Rebalance', 'Order Queue', 'History'];

// =============================================================================
// Scale Modal
// =============================================================================
function ScaleModal({ position, mode, onClose, onSubmit }) {
  const [qty, setQty] = useState('');
  const [pct, setPct] = useState(50);
  const [limitPrice, setLimitPrice] = useState('');
  const [orderType, setOrderType] = useState('LIMIT');
  const [reason, setReason] = useState('');
  const [usePercent, setUsePercent] = useState(mode === 'out');
  const [submitting, setSubmitting] = useState(false);

  const currentQty = Math.abs(position?.qty || position?.position || 0);
  const avgCost = position?.avg_cost || position?.entryPrice || 0;

  const computedShares = usePercent
    ? Math.round(currentQty * (pct / 100) * 10000) / 10000
    : parseFloat(qty) || 0;

  async function handleSubmit() {
    setSubmitting(true);
    try {
      const symbol = position.symbol;
      if (mode === 'out') {
        await onSubmit(symbol, {
          shares: usePercent ? undefined : parseFloat(qty),
          percentage: usePercent ? pct : undefined,
          limit_price: limitPrice ? parseFloat(limitPrice) : undefined,
          order_type: orderType,
          reason,
        }, 'out');
      } else {
        await onSubmit(symbol, {
          shares: parseFloat(qty) || undefined,
          dollars: undefined,
          limit_price: limitPrice ? parseFloat(limitPrice) : undefined,
          order_type: orderType,
          reason,
        }, 'in');
      }
      onClose();
    } catch (e) {
      alert(e?.message || 'Failed');
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className={s.modalOverlay}
      onClick={onClose}
    >
      <motion.div
        initial={{ scale: 0.9, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        exit={{ scale: 0.9, opacity: 0 }}
        className={`${s.card} ${s.modalContent}`}
        onClick={(e) => e.stopPropagation()}
      >
        <div className={s.modalTitle}>
          {mode === 'out' ? 'Scale Out' : 'Scale In'} -- {position?.symbol}
        </div>
        <div className={s.modalSubtitle}>
          Current: {currentQty} shares @ {fmtDollar(avgCost)}
        </div>

        {mode === 'out' && (
          <div className={s.modalToggleRow}>
            <button className={`${s.pill} ${usePercent ? s.pillActive : s.pillInactive}`} onClick={() => setUsePercent(true)}>By %</button>
            <button className={`${s.pill} ${!usePercent ? s.pillActive : s.pillInactive}`} onClick={() => setUsePercent(false)}>By Shares</button>
          </div>
        )}

        {(mode === 'in' || !usePercent) && (
          <div className={s.modalField}>
            <label className={s.fieldLabel}>Shares</label>
            <input
              type="number"
              className={s.input}
              value={qty}
              onChange={(e) => setQty(e.target.value)}
              placeholder={mode === 'out' ? `Max ${currentQty}` : 'Shares to add'}
              min={0}
              max={mode === 'out' ? currentQty : undefined}
            />
          </div>
        )}

        {mode === 'out' && usePercent && (
          <div className={s.modalField}>
            <label className={s.fieldLabel}>
              Percentage: {pct}% ({computedShares.toFixed(2)} shares)
            </label>
            <input
              type="range"
              min={5}
              max={100}
              step={5}
              value={pct}
              onChange={(e) => setPct(Number(e.target.value))}
              className={s.rangeBar}
              style={{ accentColor: C.blue }}
            />
            <div className={s.rangeLabels}>
              <span>5%</span><span>25%</span><span>50%</span><span>75%</span><span>100%</span>
            </div>
          </div>
        )}

        <div className={s.modalField}>
          <label className={s.fieldLabel}>Limit Price (optional)</label>
          <input
            type="number"
            className={s.input}
            value={limitPrice}
            onChange={(e) => setLimitPrice(e.target.value)}
            placeholder="Leave blank for market"
          />
        </div>

        <div className={s.orderTypeRow}>
          <button className={`${s.pill} ${orderType === 'LIMIT' ? s.pillActive : s.pillInactive}`} onClick={() => setOrderType('LIMIT')}>LIMIT</button>
          <button className={`${s.pill} ${orderType === 'MARKET' ? s.pillActive : s.pillInactive}`} onClick={() => setOrderType('MARKET')}>MARKET</button>
        </div>

        <div className={s.modalFieldLarge}>
          <label className={s.fieldLabel}>Reason (optional)</label>
          <input
            type="text"
            className={s.input}
            value={reason}
            onChange={(e) => setReason(e.target.value)}
            placeholder="e.g. Taking profit at resistance"
          />
        </div>

        <div className={s.modalFooter}>
          <button className={s.btnGhost} onClick={onClose}>Cancel</button>
          <button
            className={mode === 'out' ? s.btnDanger : s.btnPrimary}
            onClick={handleSubmit}
            disabled={submitting || (mode === 'in' && !qty) || (mode === 'out' && !usePercent && !qty)}
          >
            {submitting ? 'Submitting...' : mode === 'out' ? 'Queue Scale Out' : 'Queue Scale In'}
          </button>
        </div>
      </motion.div>
    </motion.div>
  );
}

// =============================================================================
// Positions Tab
// =============================================================================
function PositionsTab({ positions, equity, onScale, loading }) {
  const totalValue = positions.reduce((s, p) => s + (p.marketValue || 0), 0);

  return (
    <motion.div variants={staggerContainer} initial="initial" animate="animate">
      {/* Summary row */}
      <motion.div variants={staggerItem} className={s.summaryRow}>
        {[
          { label: 'Positions', value: positions.length, color: C.blue },
          { label: 'Total Value', value: fmtDollar(totalValue), color: C.textPrimary },
          { label: 'Account Equity', value: fmtDollar(equity), color: C.textPrimary },
          { label: 'Invested %', value: equity > 0 ? `${((totalValue / equity) * 100).toFixed(1)}%` : '--', color: C.amber },
        ].map((m) => (
          <div key={m.label} className={s.summaryCard}>
            <div className={s.summaryLabel}>{m.label}</div>
            <div className={s.summaryValue} style={{ color: m.color }}>{m.value}</div>
          </div>
        ))}
      </motion.div>

      {/* Position table */}
      <motion.div variants={staggerItem} className={s.cardFlush}>
        {loading ? (
          <div className={s.emptyState}>Loading positions...</div>
        ) : positions.length === 0 ? (
          <div className={s.emptyState}>No open positions</div>
        ) : (
          <table className={s.table}>
            <thead>
              <tr>
                {['Symbol', 'Side', 'Qty', 'Entry', 'Current', 'P&L', 'P&L %', 'Weight %', 'Value', 'Actions'].map((h) => (
                  <th key={h}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {positions.map((p) => {
                const mktVal = p.marketValue || 0;
                const weight = equity > 0 ? ((mktVal / equity) * 100).toFixed(1) : '--';
                return (
                  <tr key={p.symbol + (p.bot || '')}>
                    <td className={s.cellBold}>{p.symbol}</td>
                    <td style={{ color: p.side === 'LONG' ? C.green : p.side === 'SHORT' ? C.red : C.textSecondary }}>{p.side || '--'}</td>
                    <td className={s.cellPrimary}>{Math.abs(p.qty || 0)}</td>
                    <td className={s.cellSecondary}>{fmtDollar(p.entryPrice)}</td>
                    <td className={s.cellPrimary}>{fmtDollar(p.currentPrice)}</td>
                    <td style={{ color: pnlColor(p.unrealizedPnl) }}>{fmtDollar(p.unrealizedPnl)}</td>
                    <td style={{ color: pnlColor(p.pctChange) }}>{fmtPct(p.pctChange)}</td>
                    <td style={{ color: C.amber }}>{weight}%</td>
                    <td className={s.cellPrimary}>{fmtDollar(mktVal)}</td>
                    <td>
                      <div className={s.actionCell}>
                        <button
                          onClick={() => onScale(p, 'in')}
                          className={`${s.btnPrimary} ${s.btnSmall} ${s.btnGreen}`}
                        >
                          + In
                        </button>
                        <button
                          onClick={() => onScale(p, 'out')}
                          className={`${s.btnPrimary} ${s.btnSmall} ${s.btnRed}`}
                        >
                          - Out
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </motion.div>
    </motion.div>
  );
}

// =============================================================================
// Rebalance Tab
// =============================================================================
function RebalanceTab({ positions, equity }) {
  const [targets, setTargets] = useState({});
  const [preview, setPreview] = useState(null);
  const [loadingPreview, setLoadingPreview] = useState(false);
  const [executing, setExecuting] = useState(false);
  const [savedMsg, setSavedMsg] = useState('');

  useEffect(() => {
    api('/positions/rebalance/targets')
      .then((r) => {
        if (r?.data?.allocations) setTargets(r.data.allocations);
      })
      .catch(() => {});
  }, []);

  useEffect(() => {
    if (positions.length > 0 && Object.keys(targets).length === 0) {
      const totalVal = positions.reduce((s, p) => s + (p.marketValue || 0), 0);
      if (totalVal > 0) {
        const init = {};
        positions.forEach((p) => {
          init[p.symbol] = parseFloat(((p.marketValue / totalVal) * 100).toFixed(1));
        });
        setTargets(init);
      }
    }
  }, [positions]);

  const totalTarget = Object.values(targets).reduce((s, v) => s + (parseFloat(v) || 0), 0);

  function updateTarget(symbol, val) {
    setTargets((prev) => ({ ...prev, [symbol]: parseFloat(val) || 0 }));
    setPreview(null);
  }

  async function saveTargets() {
    try {
      await api('/positions/rebalance/targets', { method: 'PUT', body: JSON.stringify({ allocations: targets }), headers: { 'Content-Type': 'application/json' } });
      setSavedMsg('Targets saved');
      setTimeout(() => setSavedMsg(''), 2000);
    } catch {
      setSavedMsg('Save failed');
    }
  }

  async function fetchPreview() {
    setLoadingPreview(true);
    try {
      const r = await api('/positions/rebalance/compute');
      setPreview(r);
    } catch (e) {
      alert(e?.message || 'Preview failed');
    } finally {
      setLoadingPreview(false);
    }
  }

  async function executeRebalance() {
    if (!window.confirm('Queue all rebalance orders for review?')) return;
    setExecuting(true);
    try {
      const r = await api('/positions/rebalance/queue', { method: 'POST' });
      alert(`Queued ${r?.count || 0} rebalance orders for review`);
      setPreview(null);
    } catch (e) {
      alert(e?.message || 'Execute failed');
    } finally {
      setExecuting(false);
    }
  }

  return (
    <motion.div variants={staggerContainer} initial="initial" animate="animate">
      {/* Target allocation editor */}
      <motion.div variants={staggerItem} className={s.card} style={{ marginBottom: 16 }}>
        <div className={s.rebalanceHeader}>
          <div>
            <div className={s.rebalanceTitle}>Target Allocations</div>
            <div className={s.rebalanceTotalLine}>
              Total: <span style={{ color: Math.abs(totalTarget - 100) < 0.5 ? C.green : C.amber }}>{totalTarget.toFixed(1)}%</span>
              {Math.abs(totalTarget - 100) >= 0.5 && <span style={{ color: C.amber, marginLeft: 8 }}>(should be ~100%)</span>}
            </div>
          </div>
          <div className={s.rebalanceActions}>
            {savedMsg && <span className={s.rebalanceSavedMsg}>{savedMsg}</span>}
            <button className={s.btnGhost} onClick={saveTargets}>Save Targets</button>
          </div>
        </div>

        <div className={s.allocationGrid}>
          {positions.map((p) => {
            const currentPct = equity > 0 ? ((p.marketValue || 0) / equity * 100) : 0;
            const tgt = targets[p.symbol] ?? 0;
            const drift = tgt - currentPct;
            return (
              <div key={p.symbol} className={s.allocationCard}>
                <div className={s.allocationHeader}>
                  <span className={s.allocationSymbol}>{p.symbol}</span>
                  <span className={s.allocationNow}>Now: {currentPct.toFixed(1)}%</span>
                </div>
                <div className={s.allocationInputRow}>
                  <input
                    type="number"
                    className={s.inputNarrow}
                    value={tgt}
                    onChange={(e) => updateTarget(p.symbol, e.target.value)}
                    min={0}
                    max={100}
                    step={0.5}
                  />
                  <span className={s.allocationPctLabel}>%</span>
                  <span
                    className={s.allocationDrift}
                    style={{ color: Math.abs(drift) < 0.5 ? C.textMuted : drift > 0 ? C.green : C.red }}
                  >
                    {drift > 0 ? '+' : ''}{drift.toFixed(1)}%
                  </span>
                </div>
                {/* Visual bar */}
                <div className={s.allocationBar}>
                  <div className={s.allocationBarCurrent} style={{ background: C.blue + '60', width: `${Math.min(currentPct, 100)}%` }} />
                  <div className={s.allocationBarTarget} style={{ left: `${Math.min(tgt, 100)}%` }} />
                </div>
              </div>
            );
          })}
        </div>

        <div className={s.rebalanceFooter}>
          <button className={s.btnPrimary} onClick={fetchPreview} disabled={loadingPreview}>
            {loadingPreview ? 'Computing...' : 'Preview Rebalance'}
          </button>
        </div>
      </motion.div>

      {/* Rebalance preview */}
      {preview && (
        <motion.div variants={staggerItem} className={s.card}>
          <div className={s.previewHeader}>
            <div className={s.previewTitle}>
              Proposed Trades ({preview.orders?.length || 0})
            </div>
            <button
              className={s.btnPrimary}
              onClick={executeRebalance}
              disabled={executing || !preview.orders?.length}
            >
              {executing ? 'Queueing...' : 'Queue All for Review'}
            </button>
          </div>

          {(preview.orders || []).length === 0 ? (
            <div className={s.previewEmpty}>
              Portfolio is within tolerance -- no rebalancing needed
            </div>
          ) : (
            <table className={s.table}>
              <thead>
                <tr>
                  {['Symbol', 'Action', 'Shares', 'Current %', 'Target %', 'Drift', 'Est. Value'].map((h) => (
                    <th key={h}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {preview.orders.map((o, i) => (
                  <tr key={i}>
                    <td className={s.cellBold}>{o.symbol}</td>
                    <td style={{ color: o.action === 'BUY' ? C.green : C.red }}>{o.action}</td>
                    <td className={s.cellPrimary}>{Math.abs(o.delta_shares || 0).toFixed(0)}</td>
                    <td className={s.cellSecondary}>{(o.current_pct || 0).toFixed(1)}%</td>
                    <td style={{ color: C.amber }}>{(o.target_pct || 0).toFixed(1)}%</td>
                    <td style={{ color: pnlColor(o.drift_pct) }}>{fmtPct(o.drift_pct)}</td>
                    <td className={s.cellPrimary}>{fmtDollar(Math.abs(o.delta_value || 0))}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </motion.div>
      )}
    </motion.div>
  );
}

// =============================================================================
// Order Queue Tab
// =============================================================================
function OrderQueueTab() {
  const [queue, setQueue] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchQueue = useCallback(async () => {
    try {
      const r = await api('/positions/queue');
      setQueue(r?.queue || []);
    } catch {
      setQueue([]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchQueue(); }, [fetchQueue]);

  async function handleAction(orderId, action) {
    try {
      await api(`/positions/queue/${orderId}/${action}`, { method: 'POST' });
      fetchQueue();
    } catch (e) {
      alert(e?.message || `${action} failed`);
    }
  }

  const actionLabel = {
    scale_in: 'Scale In',
    scale_out: 'Scale Out',
    set_stops: 'Set Stops',
    rebalance_buy: 'Rebalance Buy',
    rebalance_sell: 'Rebalance Sell',
  };

  return (
    <motion.div variants={staggerContainer} initial="initial" animate="animate">
      <motion.div variants={staggerItem} className={s.cardFlush}>
        <div className={s.queueHeader}>
          <span className={s.queueTitle}>Pending Orders</span>
          <button className={s.refreshBtn} onClick={fetchQueue}>Refresh</button>
        </div>

        {loading ? (
          <div className={s.emptyState}>Loading...</div>
        ) : queue.length === 0 ? (
          <div className={s.emptyState}>
            No pending orders. Scale or rebalance to create queued orders.
          </div>
        ) : (
          <table className={s.table}>
            <thead>
              <tr>
                {['Symbol', 'Action', 'Shares', 'Price', 'Side', 'Created', 'Reason', 'Actions'].map((h) => (
                  <th key={h}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {queue.map((o) => (
                <tr key={o.id}>
                  <td className={s.cellBold}>{o.symbol}</td>
                  <td style={{ color: C.amber }}>{actionLabel[o.action] || o.action}</td>
                  <td className={s.cellPrimary}>
                    {o.add_shares || o.reduce_shares || o.shares || '--'}
                  </td>
                  <td className={s.cellSecondary}>
                    {o.limit_price ? fmtDollar(o.limit_price) : 'MKT'}
                  </td>
                  <td style={{ color: o.side === 'LONG' ? C.green : C.red }}>{o.side || '--'}</td>
                  <td className={`${s.cellMuted} ${s.cellSmall}`}>{timeAgo(o.created_at)}</td>
                  <td className={s.cellTruncate}>
                    {o.reason || '--'}
                  </td>
                  <td>
                    <div className={s.actionCellSmall}>
                      <button
                        className={`${s.btnPrimary} ${s.btnXSmall} ${s.btnGreen}`}
                        onClick={() => handleAction(o.id, 'approve')}
                      >
                        Approve
                      </button>
                      <button
                        className={`${s.btnPrimary} ${s.btnXSmall} ${s.btnRed}`}
                        onClick={() => handleAction(o.id, 'reject')}
                      >
                        Reject
                      </button>
                      <button
                        className={`${s.btnGhost} ${s.btnXSmall}`}
                        onClick={() => handleAction(o.id, 'cancel')}
                      >
                        Cancel
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </motion.div>
    </motion.div>
  );
}

// =============================================================================
// History Tab
// =============================================================================
function HistoryTab({ positions }) {
  const [selectedSymbol, setSelectedSymbol] = useState('');
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(false);

  const symbols = useMemo(() => positions.map((p) => p.symbol).filter(Boolean).sort(), [positions]);

  useEffect(() => {
    if (symbols.length > 0 && !selectedSymbol) {
      setSelectedSymbol(symbols[0]);
    }
  }, [symbols]);

  useEffect(() => {
    if (!selectedSymbol) return;
    setLoading(true);
    api(`/positions/${selectedSymbol}/history?limit=50`)
      .then((r) => setHistory(r?.history || []))
      .catch(() => setHistory([]))
      .finally(() => setLoading(false));
  }, [selectedSymbol]);

  return (
    <motion.div variants={staggerContainer} initial="initial" animate="animate">
      {/* Symbol selector */}
      <motion.div variants={staggerItem} className={s.symbolSelector}>
        {symbols.map((sym) => (
          <button key={sym} className={`${s.pill} ${selectedSymbol === sym ? s.pillActive : s.pillInactive}`} onClick={() => setSelectedSymbol(sym)}>{sym}</button>
        ))}
      </motion.div>

      <motion.div variants={staggerItem} className={s.cardFlush}>
        {loading ? (
          <div className={s.emptyState}>Loading history...</div>
        ) : history.length === 0 ? (
          <div className={s.emptyState}>
            {selectedSymbol ? `No execution history for ${selectedSymbol}` : 'Select a symbol'}
          </div>
        ) : (
          <table className={s.table}>
            <thead>
              <tr>
                {['Time', 'Side', 'Qty', 'Price', 'Source', 'Status'].map((h) => (
                  <th key={h}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {history.map((h, i) => (
                <tr key={h.id || i}>
                  <td className={`${s.cellMuted} ${s.cellSmall}`}>
                    {h.timestamp ? new Date(h.timestamp).toLocaleString() : '--'}
                  </td>
                  <td style={{ color: h.side === 'BUY' ? C.green : h.side === 'SELL' ? C.red : C.textSecondary }}>
                    {h.side || '--'}
                  </td>
                  <td className={s.cellPrimary}>{h.qty || '--'}</td>
                  <td className={s.cellPrimary}>{h.price ? fmtDollar(h.price) : '--'}</td>
                  <td className={s.cellSecondary}>
                    <span
                      className={s.sourceBadge}
                      style={{
                        background: h.source === 'ibkr' ? C.blue + '20' : h.source === 'engine' ? C.purple + '20' : C.amber + '20',
                        color: h.source === 'ibkr' ? C.blue : h.source === 'engine' ? C.purple : C.amber,
                      }}
                    >
                      {h.source || 'unknown'}
                    </span>
                  </td>
                  <td className={s.cellSecondary}>
                    <span
                      className={s.statusBadge}
                      style={{
                        background: h.status === 'Filled' ? C.green + '20' : h.status === 'pending_review' ? C.amber + '20' : C.textMuted + '20',
                        color: h.status === 'Filled' ? C.green : h.status === 'pending_review' ? C.amber : C.textMuted,
                      }}
                    >
                      {h.status || '--'}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </motion.div>
    </motion.div>
  );
}

// =============================================================================
// Main Page
// =============================================================================
export default function PositionManagementPage() {
  usePageTitle('Position Management');
  const isMobile = useIsMobile();
  const [tab, setTab] = useState(0);
  const [positions, setPositions] = useState([]);
  const [equity, setEquity] = useState(0);
  const [loading, setLoading] = useState(true);
  const [scaleModal, setScaleModal] = useState(null);

  const fetchPositions = useCallback(async () => {
    try {
      const r = await api('/positions');
      setPositions(r?.positions || []);
    } catch {
      setPositions([]);
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchEquity = useCallback(async () => {
    try {
      const r = await api('/telemetry/latest');
      const accounts = r?.gateway || {};
      let total = 0;
      for (const acct of Object.values(accounts)) {
        if (acct?.equity) total += acct.equity;
        else if (acct?.net_liquidation) total += acct.net_liquidation;
      }
      if (total > 0) setEquity(total);
    } catch {}
  }, []);

  useEffect(() => {
    fetchPositions();
    fetchEquity();
    const iv = setInterval(() => { fetchPositions(); fetchEquity(); }, 30000);
    return () => clearInterval(iv);
  }, [fetchPositions, fetchEquity]);

  async function handleScale(symbol, req, mode) {
    const endpoint = mode === 'out'
      ? `/api/positions/${symbol}/scale-out`
      : `/api/positions/${symbol}/scale-in`;
    const r = await api(endpoint, {
      method: 'POST',
      body: JSON.stringify(req),
      headers: { 'Content-Type': 'application/json' },
    });
    if (r?.error) throw new Error(r.error);
    return r;
  }

  return (
    <AnimatedPage>
      <div className={isMobile ? s.pageMobile : s.page}>
        {/* Header */}
        <div className={s.header}>
          <h1 className={s.pageTitle}>Position Management</h1>
          <p className={s.pageSubtitle}>
            Scale in/out, rebalance portfolio, manage order queue
          </p>
        </div>

        {/* Tab bar */}
        <div className={s.tabBar}>
          {tabNames.map((t, i) => (
            <motion.button
              key={t}
              className={`${s.pill} ${tab === i ? s.pillActive : s.pillInactive}`}
              onClick={() => setTab(i)}
              whileTap={{ scale: 0.96 }}
            >
              {t}
            </motion.button>
          ))}
        </div>

        {/* Tab content */}
        <AnimatePresence mode="wait">
          {tab === 0 && (
            <motion.div key="positions" {...fadeIn}>
              <PositionsTab
                positions={positions}
                equity={equity}
                loading={loading}
                onScale={(p, mode) => setScaleModal({ position: p, mode })}
              />
            </motion.div>
          )}
          {tab === 1 && (
            <motion.div key="rebalance" {...fadeIn}>
              <RebalanceTab positions={positions} equity={equity} />
            </motion.div>
          )}
          {tab === 2 && (
            <motion.div key="queue" {...fadeIn}>
              <OrderQueueTab />
            </motion.div>
          )}
          {tab === 3 && (
            <motion.div key="history" {...fadeIn}>
              <HistoryTab positions={positions} />
            </motion.div>
          )}
        </AnimatePresence>

        {/* Scale modal */}
        <AnimatePresence>
          {scaleModal && (
            <ScaleModal
              position={scaleModal.position}
              mode={scaleModal.mode}
              onClose={() => setScaleModal(null)}
              onSubmit={handleScale}
            />
          )}
        </AnimatePresence>
      </div>
    </AnimatedPage>
  );
}
